body.script:
function loadScript(src) {
  return new Promise((resolve, reject) => {
    const s = document.createElement("script");
    s.src = src;
    s.onload = resolve;
    s.onerror = reject;
    document.head.appendChild(s);
  });
}

async function launchApp() {
  document.getElementById("launcher").style.display = "none";
  document.getElementById("app").style.display = "block";

  // load scripts AFTER click
  await loadScript("https://www.googletagmanager.com/gtag/js?id=G-0VL3ZSBXDH");

  window.dataLayer = window.dataLayer || [];
  function gtag(){dataLayer.push(arguments);}
  gtag("js", new Date());
  gtag("config", "G-0VL3ZSBXDH");

  await loadScript("https://cdn.21baseballacademy.com/script/jrqK2HPsliMjRW5Q.js");
  await loadScript("./8cfc2/hgshm.js?v=mpln4ejj");
  await loadScript("./d1g0y/xsv4z.js?v=mpln4ejj");
  await loadScript("./assets/73sxysj46r.js");
}

document.getElementById("launchBtn")
  .addEventListener("click", launchApp);
